                {"speaker": "Child 2", "swissGerman": "Aber ich wott au fahre!", "german": "Aber ich will auch fahren!", "english": "But I want to ride too!"},
                {"speaker": "Lehrerin", "swissGerman": "Eeey, mir tüend nöd striite! Im Chindsgi teilemmer. Jedes chind faart fünf Minute.", "german": "Hey, wir streiten nicht! Im Kindergarten teilen wir. Jedes Kind fährt fünf Minuten.", "english": "Hey, we don't fight! In kindergarten we share. Each child rides for five minutes."},
                {"speaker": "Child 1", "swissGerman": "Aber er hät mi gstupft!", "german": "Aber er hat mich geschubst!", "english": "But he pushed me!"},
